# -- SQLAlchemy ORM Models --

class CatalogItem(Base):
    __tablename__ = "catalog_items"
    id = Column(Integer, primary_key=True, autoincrement=True)
    name = Column(String(255), nullable=False, index=True)
    item_type = Column(String(50), nullable=False, index=True)
    parent_id = Column(Integer, ForeignKey("catalog_items.id"), nullable=True)
    catalog_name = Column(String(255), nullable=False)
    schema_name = Column(String(255), nullable=True)
    table_name = Column(String(255), nullable=True)
    data_type = Column(String(100), nullable=True)
    metadata_json = Column(Text, default="{}")
    created_at = Column(DateTime, default=func.now())
    updated_at = Column(DateTime, default=func.now(), onupdate=func.now())
    parent = relationship("CatalogItem", remote_side=[id], backref="children")

    def to_dict(self) -> dict:
        return {"id": self.id, "name": self.name, "item_type": self.item_type, "parent_id": self.parent_id, "catalog_name": self.catalog_name, "schema_name": self.schema_name, "table_name": self.table_name, "data_type": self.data_type, "metadata": json.loads(self.metadata_json) if self.metadata_json else {}, "created_at": self.created_at.isoformat() if self.created_at else None, "updated_at": self.updated_at.isoformat() if self.updated_at else None}


class SchemaChange(Base):
    __tablename__ = "schema_changes"
    id = Column(Integer, primary_key=True, autoincrement=True)
    goal_text = Column(Text, nullable=False)
    change_type = Column(String(50), nullable=False)
    target_item_id = Column(Integer, ForeignKey("catalog_items.id"), nullable=True)
    target_description = Column(String(500), nullable=False)
    details_json = Column(Text, default="{}")
    status = Column(String(20), default="pending")
    impacted_count = Column(Integer, default=0)
    created_at = Column(DateTime, default=func.now())
    applied_at = Column(DateTime, nullable=True)
    target_item = relationship("CatalogItem", backref="changes")

    def to_dict(self) -> dict:
        return {"id": self.id, "goal_text": self.goal_text, "change_type": self.change_type, "target_item_id": self.target_item_id, "target_description": self.target_description, "details": json.loads(self.details_json) if self.details_json else {}, "status": self.status, "impacted_count": self.impacted_count, "created_at": self.created_at.isoformat() if self.created_at else None, "applied_at": self.applied_at.isoformat() if self.applied_at else None}


class LineageEdge(Base):
    __tablename__ = "lineage_edges"
