<div class="main">
<div id="page-changes" class="page active">
<h2>Schema Change Tracker</h2>
<div class="stats-bar" id="stats-bar"></div>
<div class="card">
<div class="goal-form"><input type="text" id="goal-input" placeholder="Enter a schema change goal, e.g. 'add column email to table users'"/><button class="btn" id="submit-goal" onclick="submitGoal()">Submit Goal</button></div>
<div id="impact-result" class="impact-panel"></div>
</div>
