</div>
<div id="page-browser" class="page">
<h2>Schema Browser</h2>
<div class="tree-container">
<div class="tree-panel"><input type="text" class="tree-search" id="tree-search" placeholder="Search items..." oninput="filterTree()"/><div id="schema-tree"><div class="loading">Loading schema...</div></div></div>
<div class="detail-panel" id="item-detail"><p class="loading">Select an item to view details</p></div>
</div>
</div>
