<div class="graph-legend"><span><span class="legend-dot" style="background:#22c55e"></span>Table</span><span><span class="legend-dot" style="background:#f59e0b"></span>View</span><span><span class="legend-dot" style="background:#a855f7"></span>Other</span></div>
</div>
<div id="lineage-graph"></div>
</div>
