<script>
const API='';
let network=null;
document.querySelectorAll('.nav-item').forEach(i=>{i.addEventListener('click',()=>{document.querySelectorAll('.nav-item').forEach(n=>n.classList.remove('active'));document.querySelectorAll('.page').forEach(p=>p.classList.remove('active'));i.classList.add('active');document.getElementById('page-'+i.dataset.page).classList.add('active');if(i.dataset.page==='graph')loadGraph();if(i.dataset.page==='browser')loadTree()})});
async function submitGoal(){const input=document.getElementById('goal-input'),btn=document.getElementById('submit-goal'),goal=input.value.trim();if(!goal)return;btn.disabled=true;btn.textContent='Processing...';try{const res=await fetch(API+'/goals',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({goal})});const data=await res.json();if(!res.ok)throw new Error(data.detail||'Failed');showImpact(data);input.value='';loadChanges()}catch(e){alert('Error: '+e.message)}btn.disabled=false;btn.textContent='Submit Goal'}
function showImpact(d){const p=document.getElementById('impact-result');let h='<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px"><strong>Change #'+d.change_id+': '+d.change_type+'</strong><span class="badge badge-'+d.status+'">'+d.status+'</span></div>';h+='<p style="color:var(--dim);font-size:13px;margin-bottom:8px">Target: '+d.target+'</p>';if(d.impacted_items&&d.impacted_items.length>0){h+='<p style="font-size:13px;margin-bottom:6px">'+d.impacted_items.length+' impacted item(s):</p><ul class="impact-list">';d.impacted_items.forEach(i=>{h+='<li><span class="type-'+i.item_type+'">'+i.item_type+'</span> '+esc(i.name)+' <span class="distance-badge">'+i.distance+' hop(s)</span></li>'});h+='</ul>'}else h+='<p style="font-size:13px;color:var(--dim)">No downstream items impacted.</p>';p.innerHTML=h;p.classList.add('show')}
async function loadChanges(){try{const r=await fetch(API+'/changes');const d=await r.json();const t=document.getElementById('changes-table');document.getElementById('changes-loading').style.display='none';if(!d.length){t.innerHTML='<tr><td colspan="6" class="loading">No changes yet.</td></tr>';return}t.innerHTML=d.map(c=>'<tr><td style="color:var(--dim);font-size:12px">'+(c.created_at?new Date(c.created_at).toLocaleString():'-')+'</td><td>'+esc(c.goal_text.substring(0,60))+(c.goal_text.length>60?'...':'')+'</td><td><code>'+c.change_type+'</code></td><td>'+esc(c.target_description)+'</td><td><span class="badge badge-'+c.status+'">'+c.status+'</span></td><td>'+c.impacted_count+'</td></tr>').join('')}catch(e){console.error(e)}}
async function loadStats(){try{const[items,changes]=await Promise.all([fetch(API+'/schema/items').then(r=>r.json()),fetch(API+'/changes').then(r=>r.json())]);const tables=items.filter(i=>i.item_type==='table').length,cols=items.filter(i=>i.item_type==='column').length;document.getElementById('stats-bar').innerHTML='<div class="stat-card"><div class="stat-value">'+items.length+'</div><div class="stat-label">Total Items</div></div><div class="stat-card"><div class="stat-value">'+tables+'</div><div class="stat-label">Tables</div></div><div class="stat-card"><div class="stat-value">'+cols+'</div><div class="stat-label">Columns</div></div><div class="stat-card"><div class="stat-value">'+changes.length+'</div><div class="stat-label">Changes</div></div>'}catch(e){}}
let allItems=[];
async function loadTree(){try{const r=await fetch(API+'/schema/items');allItems=await r.json();renderTree(allItems)}catch(e){document.getElementById('schema-tree').innerHTML='<p class="loading">Failed to load</p>'}}
function renderTree(items){const cats={};items.forEach(i=>{if(i.item_type==='catalog')cats[i.name]={item:i,schemas:{}}});items.forEach(i=>{if(i.item_type==='schema'&&cats[i.catalog_name])cats[i.catalog_name].schemas[i.name]={item:i,tables:{}}});items.forEach(i=>{if(['table','view'].includes(i.item_type)&&cats[i.catalog_name]&&cats[i.catalog_name].schemas[i.schema_name])cats[i.catalog_name].schemas[i.schema_name].tables[i.name]={item:i,columns:[]}});items.forEach(i=>{if(i.item_type==='column'&&cats[i.catalog_name]&&cats[i.catalog_name].schemas[i.schema_name]&&cats[i.catalog_name].schemas[i.schema_name].tables[i.table_name])cats[i.catalog_name].schemas[i.schema_name].tables[i.table_name].columns.push(i)});let h='';for(const[cn,cat]of Object.entries(cats)){h+='<div class="tree-node"><span class="tree-toggle" onclick="tog(this)">&#9654;</span> <span class="tree-icon type-catalog">&#9632;</span><span onclick="showDetail('+cat.item.id+')">' +cn+'</span></div><div class="tree-children">';for(const[sn,sch]of Object.entries(cat.schemas)){h+='<div class="tree-node"><span class="tree-toggle" onclick="tog(this)">&#9654;</span> <span class="tree-icon type-schema">&#9632;</span><span onclick="showDetail('+sch.item.id+')">' +sn+'</span></div><div class="tree-children">';for(const[tn,tbl]of Object.entries(sch.tables)){const ic=tbl.item.item_type==='view'?'type-view':'type-table';h+='<div class="tree-node"><span class="tree-toggle" onclick="tog(this)">&#9654;</span> <span class="tree-icon '+ic+'">&#9632;</span><span onclick="showDetail('+tbl.item.id+')">' +tn+'</span></div><div class="tree-children">';tbl.columns.forEach(col=>{h+='<div class="tree-node"><span class="tree-icon type-column">&#9702;</span><span onclick="showDetail('+col.id+')">' +col.name+' <span style="color:var(--dim);font-size:11px">'+(col.data_type||'')+'</span></span></div>'});h+='</div>'}h+='</div>'}h+='</div>'}document.getElementById('schema-tree').innerHTML=h||'<p class="l"
